window.__ml5Ready = new Promise((resolve, reject) => {
  if (window.ml5) {
    resolve(window.ml5);
    return;
  }

  const script = document.createElement("script");
  script.src = "https://cdn.jsdelivr.net/npm/ml5@1/dist/ml5.min.js";
  script.onload = () => resolve(window.ml5);
  script.onerror = () => reject(new Error("No se pudo cargar ml5.js"));
  document.head.appendChild(script);
});
